  1	import * as React from 'react';
  2	import { Button, Tabs, Tab, ButtonVariant } from '@patternfly/react-core';
  3	import { K8sMatchBuilder } from './K8sMatchBuilder';
  4	import { K8sMatches } from './K8sMatches';
  5	import { kialiStyle } from 'styles/StyleUtils';
  6	import { PFColors } from '../../Pf/PfColors';
  7	import { K8sTrafficShifting, K8sRouteBackendRef } from '../K8sTrafficShifting';
  8	import { ServiceOverview } from '../../../types/ServiceList';
  9	import { K8sFilterBuilder } from './K8sFilterBuilder';
 10	import { K8sFilters } from './K8sFilters';
 11	
 12	type Props = {
 13	  // K8sRuleBuilder props
 14	  backendRefs: K8sRouteBackendRef[];
 15	  category: string;
 16	  filterType: string;
 17	  filterValue: string;
 18	  filters: string[];
 19	  headerName: string;
 20	  headerOp: string;
 21	  headerValue: string;
 22	  hostName: string;
 23	  isValid: boolean;
 24	  matchValue: string;
 25	  matches: string[];
 26	  methodName: string;
 27	  methodService: string;
 28	  onAddFilter: () => void;
 29	  onAddMatch: () => void;
 30	  onAddRule: () => void;
 31	  onHeaderNameChange: (headerName: string) => void;
 32	  onHeaderValueChange: (headerValue: string) => void;
 33	  onHostNameChange: (hostName: string) => void;
 34	  onMatchHeaderNameChange: (headerName: string) => void;
 35	  onMatchMethodNameChange: (methodName: string) => void;
 36	  onMatchMethodServiceChange: (methodService: string) => void;
 37	  onMatchValueChange: (matchValue: string) => void;
 38	  onPortValueChange: (portValue: string) => void;
 39	  onQueryParamNameChange: (matchValue: string) => void;
 40	  onRemoveFilter: (filter: string) => void;
 41	  onRemoveMatch: (match: string) => void;
 42	  onSelectCategory: (category: string) => void;
 43	  onSelectFilterType: (filterType: string) => void;
 44	  onSelectHeaderOp: (headerOp: string) => void;
 45	  onSelectOperator: (operator: string) => void;
 46	  onSelectSchemeOp: (schemeOp: string) => void;
 47	  onSelectServiceOp: (serviceOp: string) => void;
 48	  onSelectStatusCodeOp: (statusCodeOp: string) => void;
 49	  onSelectWeights: (backendRefs: K8sRouteBackendRef[]) => void;
 50	  operator: string;
 51	  portValue: string;
 52	  protocol: string;
 53	  queryParamName: string;
 54	  schemeOp: string;
 55	  serviceOp: string;
 56	  statusCodeOp: string;
 57	  subServices: ServiceOverview[];
 58	  validationMsg: string;
 59	};
 60	
 61	type State = {
 62	  isWorkloadSelector: boolean;
 63	  ruleTabKey: number;
 64	};
 65	
 66	const addRuleStyle = kialiStyle({
 67	  width: '100%',
 68	  textAlign: 'right'
 69	});
 70	
 71	const validationStyle = kialiStyle({
 72	  marginRight: 20,
 73	  color: PFColors.Red100,
 74	  display: 'inline'
 75	});
 76	
 77	export class K8sRuleBuilder extends React.Component<Props, State> {
 78	  constructor(props: Props) {
 79	    super(props);
 80	    this.state = {
 81	      isWorkloadSelector: false,
 82	      ruleTabKey: 0
 83	    };
 84	  }
 85	
 86	  onWorkloadsToggle = (): void => {
 87	    this.setState({
 88	      isWorkloadSelector: !this.state.isWorkloadSelector
 89	    });
 90	  };
 91	
 92	  ruleHandleTabClick = (_event: React.MouseEvent, tabIndex: string | number): void => {
 93	    this.setState({
 94	      ruleTabKey: tabIndex as number
 95	    });
 96	  };
 97	
 98	  render(): React.ReactNode {
 99	    return (
100	      <>
101	        <Tabs isFilled={true} activeKey={this.state.ruleTabKey} onSelect={this.ruleHandleTabClick}>
102	          <Tab eventKey={0} title={'Request Matching'} data-test={'Request Matching'}>
103	            <div style={{ marginTop: '20px' }}>
104	              <K8sMatchBuilder {...this.props} />
105	              <K8sMatches {...this.props} />
106	            </div>
107	          </Tab>
108	          <Tab eventKey={1} title={'Route To'} data-test={'Route To'}>
109	            <div
110	              style={{
111	                marginBottom: '10px'
112	              }}
113	            >
114	              <K8sTrafficShifting
115	                showValid={false}
116	                subServices={this.props.subServices}
117	                initRefs={this.props.backendRefs}
118	                onChange={this.props.onSelectWeights}
119	              />
120	            </div>
121	          </Tab>
122	          <Tab eventKey={2} title={'Route Filtering'} data-test={'Route Filtering'}>
123	            <div style={{ marginTop: '20px' }}>
124	              <K8sFilterBuilder {...this.props} />
125	              <K8sFilters {...this.props} />
126	            </div>
127	          </Tab>
128	        </Tabs>
129	        <div className={addRuleStyle}>
130	          <span>
131	            {this.props.validationMsg.length > 0 && <div className={validationStyle}>{this.props.validationMsg}</div>}
132	            <Button
133	              variant={ButtonVariant.secondary}
134	              isDisabled={!this.props.isValid}
135	              onClick={this.props.onAddRule}
136	              data-test="add-route"
137	            >
138	              Add Route Rule
139	            </Button>
140	          </span>
141	        </div>
142	      </>
143	    );
144	  }
145	}

